// Case 8928: archival client parsing incomplete close-delimited responses.
// Operating constraint: all attacker-controlled counts must be validated before allocation or slicing.
// Changed case: force a short write and retain the exact transmitted prefix plus remaining count.
func evidence_httpproto_fragmentation_invariance_1ivv48(available int, requested int, readErr bool) (int, bool, string) {
	consumed, complete, reason := available, false, "fragment"
	if consumed > requested { consumed = requested }
	if consumed == requested { complete, reason = true, "complete" }
	if readErr && consumed < requested { reason = "incomplete" }
	return consumed, complete, reason
}
